; The "details of properties" include property_id, legal_description, local_value, ptad_value, ratio, and assessment_date; 
; "most recent assessors" refers to the assessors who performed the latest assessments for each property; 
; "latest adjustments" refers to the most recent adjustments for each property; 
; "recent tax calculations and payment statuses" refer to the tax calculations and payment statuses for the most recent year for each property.

sql:
SELECT property_id, COUNT(log_id) AS assessment_count
FROM assessment_logs
GROUP BY property_id;
